mapper.select:
SELECT finance_seq AS financeSeq, user_seq AS userSeq, type, amount, category, description, target_date AS targetDate, created_at AS createdAt FROM finances WHERE user_seq = #{userSeq}
AND target_date >= #{startDate}
AND target_date <= #{endDate}
AND type = #{type}
ORDER BY target_date DESC, finance_seq DESC

mapper.insert:
INSERT INTO finances (
    user_seq, type, amount, category, description, target_date, created_at
) VALUES (
    #{userSeq}, #{type}, #{amount}, #{category}, #{description}, #{targetDate}, CURRENT_TIMESTAMP
)
